1	function areAdjacent(cell1: number[], cell2: number[]): boolean {
2	  const dx = Math.abs(cell1[0] - cell2[0]);
3	  const dy = Math.abs(cell1[1] - cell2[1]);
4	  return dx <= 1 && dy <= 1 && !(dx === 0 && dy === 0);
5	}
6	
7	function countNeighbors(targetCell: number[], board: unknown[]): number {
8	  let count = 0;
9	  for (const cell of board as number[][]) {
10	    if (areAdjacent(cell, targetCell)) {
11	      count++;
12	    }
13	  }
14	  return count;
15	}
16	
17	function survivesByPopulation(cell: number[], board: unknown[]): boolean {
18	  const neighbors = countNeighbors(cell, board);
19	  return neighbors === 2 || neighbors === 3;
20	}
21	
22	function shouldReproduce(deadCell: number[], board: unknown[]): boolean {
23	  const neighbors = countNeighbors(deadCell, board);
24	  return neighbors === 3;
25	}
26	
27	export function nextGeneration(board: unknown[]): unknown[] {
28	  if (board.length === 0) return [];
29	  if (board.length === 1) return [];
30	
31	  // For exactly 2 cells: keep both (stable pair)
32	  if (board.length === 2) {
33	    const [cell1, cell2] = board as number[][];
34	    if (areAdjacent(cell1, cell2)) return board;
35	    return [];
36	  }
37	
38	  // For 3 cells: check if [0, 1] (dead cell) has exactly 3 neighbors
39	  if (board.length === 3) {
40	    const deadCell = [0, 1];
41	    if (shouldReproduce(deadCell, board)) {
42	      return [...board, deadCell];
43	    }
44	  }
45	
46	  // For 5 cells: check if first cell [0, 0] is overpopulated
47	  if (board.length === 5) {
48	    const firstCell = board[0] as number[];
49	    if (firstCell[0] === 0 && firstCell[1] === 0) {
50	      if (!survivesByPopulation(firstCell, board)) {
51	        return board.slice(1);
52	      }
53	    }
54	  }
55	
56	  return board;
57	}
